const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  let serviceName = 'Unknown';
  let apiUrl = '';
  try {
    serviceName = $('Extract Name & URL').all()[i].json.service_name || 'Unknown';
    apiUrl = $('Extract Name & URL').all()[i].json.api_url || '';
  } catch(e) {}

  // Derive status page URL from API URL
  let statusPageUrl = '';
  try {
    const u = new URL(apiUrl);
    statusPageUrl = u.origin;
  } catch(e) {}

  const body = item.json.body || item.json;

  let indicator = 'unknown';
  let description = 'Could not parse status';

  if (body && body.page && body.status && body.status.indicator) {
    indicator = body.status.indicator;
    description = body.status.description || '';
    if (body.page.url) statusPageUrl = body.page.url;
  }
  else if (body && body.status && typeof body.status === 'object' && body.status.indicator) {
    indicator = body.status.indicator;
    description = body.status.description || '';
  }
  else if (body && body.status !== undefined && typeof body.status === 'string') {
    const s = body.status.toLowerCase();
    indicator = (s === 'ok' || s === 'active') ? 'none' : s;
    description = (s === 'ok' || s === 'active') ? 'All Systems Operational' : body.status;
  }
  else if (typeof body === 'string') {
    try {
      const parsed = JSON.parse(body);
      if (parsed.status && typeof parsed.status === 'object' && parsed.status.indicator) {
        indicator = parsed.status.indicator;
        description = parsed.status.description || '';
        if (parsed.page && parsed.page.url) statusPageUrl = parsed.page.url;
      }
    } catch(e) {}
  }

  const isHealthy = indicator === 'none';

  results.push({
    json: {
      service_name: serviceName,
      indicator: indicator,
      description: description,
      is_healthy: isHealthy,
      status_page_url: statusPageUrl,
      checked_at: new Date().toLocaleString('en-GB', { 
        day: '2-digit', month: '2-digit', year: 'numeric',
        hour: '2-digit', minute: '2-digit', hour12: false 
      })
    }
  });
}

return results;

// Dedupe gate: only alert once per service incident
const staticData = $getWorkflowStaticData('global');
if (!staticData.incidents) staticData.incidents = {};

const service = $json.service_name;
const currentIndicator = $json.indicator;

if (staticData.incidents[service] === currentIndicator) {
  // Already alerted for this exact incident state, suppress
  return [];
}

// New incident or escalation — mark and let alert through
staticData.incidents[service] = currentIndicator;
return [$input.item];

